        transparent={opacity < 1.0}
        opacity={opacity}
        polygonOffset
        polygonOffsetFactor={isGhost ? 2 : 1}
        polygonOffsetUnits={1}
      />
      {!isGhost && <Edges color={edgeColor} />}
    </mesh>
  );
};

