                const y3_1 = y2 + h * (dz / d); 
                const z3_1 = z2 - h * (dy / d); 
                const y3_2 = y2 - h * (dz / d);
                const z3_2 = z2 + h * (dy / d);

                pKnee = (y3_1*y3_1 + z3_1*z3_1 > y3_2*y3_2 + z3_2*z3_2) 
                    ? new THREE.Vector3(localX, y3_1, z3_1) 
                    : new THREE.Vector3(localX, y3_2, z3_2);
