             const riserColor = isImpossible ? '#a855f7' : '#fdfbf7';
             const treadColor = isImpossible ? '#d8b4fe' : '#fdfbf7';

             const diffRiser = new THREE.Vector3().subVectors(pKnee, pTop);
             const lenRiser = diffRiser.length();
             if (lenRiser > 0.01) {
