                    <StripPlane width={strip.width} height={lenRiser} color={riserColor} tension={tension} isGhost={isGhost} showStress={showStress} opacity={opacity} />
                  </group>
                );
             }

             const diffTread = new THREE.Vector3().subVectors(pBot, pKnee);
             const lenTread = diffTread.length();
             if (lenTread > 0.01) {
