                    <StripPlane width={strip.width} height={lenTread} color={treadColor} tension={tension} isGhost={isGhost} showStress={showStress} opacity={opacity} />
                  </group>
                );
             }
        }

        if (i < strips.length - 1 && gap > 0) {
            const gapX = localX + strip.width/2 + gap/2;
            els.push(
