    const { showGhostTrails, lampAngle, lampHeight, lampDistance } = props.params;

    const angleRad = (lampAngle * Math.PI) / 180;
    const lightPos: [number, number, number] = [
        Math.sin(angleRad) * lampDistance,
        lampHeight,
        Math.cos(angleRad) * lampDistance
