            <color attach="background" args={['#f8fafc']} />
            <ambientLight intensity={0.5} />

            <primitive object={lightTargetRef.current} position={[0, 0, 0]} />

            <spotLight 
                target={lightTargetRef.current}
                position={lightPos} 
                angle={0.6} 
                penumbra={0.5} 
                intensity={1.0} 
                castShadow 
                shadow-bias={-0.0001}
                shadow-mapSize-width={2048}
                shadow-mapSize-height={2048}
            />
            <mesh position={lightPos}>
                <sphereGeometry args={[5]} />
                <meshBasicMaterial color="#fbbf24" />
            </mesh>

            <pointLight position={[0, 100, -300]} intensity={0.4} color="#e0f2fe" />

            <group position={[0, -50, 0]}>
                {showGhostTrails && (
                    <>
                        <KirigamiMesh {...props} foldProgress={props.foldProgress * 0.3} opacity={0.2} isGhost />
                        <KirigamiMesh {...props} foldProgress={props.foldProgress * 0.6} opacity={0.3} isGhost />
                        <KirigamiMesh {...props} foldProgress={props.foldProgress * 0.8} opacity={0.4} isGhost />
                    </>
                )}
                <KirigamiMesh {...props} />
                <mesh rotation={[-Math.PI/2, 0, 0]} position={[0, -1, 0]} receiveShadow>
                     <planeGeometry args={[2000, 2000]} />
                     <meshStandardMaterial color="#f1f5f9" roughness={0.8} metalness={0.1} />
                </mesh>
                <gridHelper args={[1000, 50, 0xcbd5e1, 0xf1f5f9]} position={[0, -0.5, 0]} />
            </group>

            <OrbitControls 
                minPolarAngle={0} 
                maxPolarAngle={Math.PI / 1.9}
                minDistance={50}
                maxDistance={1200}
                target={[0, 50, 0]}
            />
        </>
    );
};

