import React, { useState, useMemo, useEffect } from 'react';
import { ControlPanel } from './components/ControlPanel';
import { BlueprintCanvas } from './components/BlueprintCanvas';
import { Visualizer3D } from './components/Visualizer3D';
import { PatternParams } from './types';
import { TUTORIAL_STEPS } from './constants';
import { generateKirigamiPattern, calculateStrips } from './geometry';

// Initial Params
const INITIAL_PARAMS: PatternParams = {
  mode: 'WAVE',
  sliceCount: 20,
  sliceWidth: 12,
  gap: 5,
  minSize: 15,

  // Wave
  amplitude: 60,
  frequency: 1.0,
  phase: 0,

  // Gaussian
  spread: 0.5,
  center: 0.5,

  // Noise
  seed: 42,
  roughness: 40,

  // Fractals
  fractalIteration: 3,
  fractalZoom: 1.0,
  fractalOffsetX: 0,
  fractalOffsetY: 0,
  branchAngle: 25,

  // Physics / Speculative
  physicsMode: 'REALISTIC',
  showStress: false,
  showGhostTrails: false,

  // Lighting
  lampAngle: 45,
  lampHeight: 400,
  lampDistance: 300,
};

function App() {
  const [params, setParams] = useState<PatternParams>(INITIAL_PARAMS);
  const [stepIndex, setStepIndex] = useState(0);
  const [foldProgress, setFoldProgress] = useState(0);

  // 1. Math Phase: Calculate abstract geometry (strips)
  const strips = useMemo(() => calculateStrips(params), [params]);

  // 2. Blueprint Phase: Convert strips to 2D lines
  const pattern = useMemo(() => generateKirigamiPattern(strips, params), [strips, params]);

  const currentStep = TUTORIAL_STEPS[stepIndex];

  // Animate Fold Progress when step changes
  useEffect(() => {
    let animationFrameId: number;
    const target = currentStep.targetFoldProgress;

    const animate = () => {
      setFoldProgress(prev => {
        const diff = target - prev;
        if (Math.abs(diff) < 0.005) return target;
        return prev + diff * 0.15; // Smooth ease
      });
      animationFrameId = requestAnimationFrame(animate);
    };

    animationFrameId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(animationFrameId);
  }, [stepIndex, currentStep.targetFoldProgress]);

  return (
    <div className="flex flex-col md:flex-row h-screen w-screen overflow-hidden bg-slate-50">

      {/* Left: Controls & Instructions */}
      <ControlPanel 
        params={params} 
        setParams={setParams} 
        currentStepIndex={stepIndex} 
        setStepIndex={setStepIndex}
        steps={TUTORIAL_STEPS}
      />

      {/* Middle: 3D Visualization */}
      <div className="flex-1 relative border-r border-slate-200">
        <div className="absolute top-4 left-4 z-10 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-xs font-semibold text-slate-600 shadow-sm border border-slate-200 flex gap-2">
           <span>3D Preview</span>
           {params.physicsMode === 'IMPOSSIBLE' && <span className="text-purple-600 font-bold">IMPOSSIBLE MODE</span>}
        </div>

        {/* Pass the calculated strips directly to the 3D visualizer */}
        <Visualizer3D params={params} strips={strips} foldProgress={foldProgress} />

        {/* Manual Fold Slider Overlay for playground feel */}
        {stepIndex === 0 && (
           <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur p-4 rounded-xl shadow-lg border border-slate-200 w-64">
             <label className="text-xs font-bold text-slate-500 uppercase mb-2 block text-center">Manual Fold Preview</label>
             <input 
               type="range" min="0" max="1" step="0.01"
               value={foldProgress}
               onChange={(e) => setFoldProgress(parseFloat(e.target.value))}
               className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-blue-500"
             />
           </div>
        )}
      </div>

      {/* Right: 2D Blueprint */}
      <div className="flex-1 relative md:w-1/3 min-w-[300px] flex flex-col">
        <div className="absolute top-4 right-4 z-10 bg-white/80 backdrop-blur px-3 py-1 rounded-full text-xs font-semibold text-slate-600 shadow-sm border border-slate-200">
          2D Blueprint
        </div>
        <BlueprintCanvas pattern={pattern} currentStep={currentStep} />
      </div>
    </div>
  );
}

export default App;

import React, { useMemo } from 'react';
import { Canvas } from '@react-three/fiber';
import { OrbitControls, Edges, ContactShadows, Environment, Center } from '@react-three/drei';
import * as THREE from 'three';
import { PatternParams, StripData } from '../types';
import { PAPER_W, PAPER_H } from '../geometry';

interface Props {
  params: PatternParams;
  strips: StripData[];
  foldProgress: number; // 0 (Flat) to 1 (Open 90 degrees)
}

const EPSILON = 0.01;

// A safe strip component that doesn't render if dimensions are invalid
const PaperStrip: React.FC<{
  width: number;
  height: number;
  color: string;
  tension?: number;
  isGhost?: boolean;
  showStress?: boolean;
  opacity?: number;
}> = ({ width, height, color, tension = 0, isGhost = false, showStress = false, opacity = 1.0 }) => {

  if (width < EPSILON || height < EPSILON) return null;

  const materialColor = useMemo(() => {
    const c = new THREE.Color(color);
    if (showStress && !isGhost) {
      // Interpolate from White -> Red based on tension
      const t = Math.min(1.0, Math.max(0, tension));
      c.lerp(new THREE.Color('#ef4444'), t * t); 
    }
    return c;
  }, [color, showStress, isGhost, tension]);

  const edgeColor = isGhost ? "#a0a0a0" : "#cbd5e1";

  return (
    <mesh>
      <planeGeometry args={[width, height]} />
      <meshStandardMaterial
        color={materialColor}
        side={THREE.DoubleSide}
        roughness={0.8}
        metalness={0.1}
        transparent={opacity < 1.0}
        opacity={opacity}
        polygonOffset={true}
        polygonOffsetFactor={isGhost ? 2 : 1}
      />
      {!isGhost && <Edges color={edgeColor} threshold={15} />}
    </mesh>
  );
};

// Calculates the 3D position of all strips based on fold progress
const KirigamiMesh: React.FC<{
  params: PatternParams;
  strips: StripData[];
  foldProgress: number;
  opacity?: number;
  isGhost?: boolean;
}> = ({ params, strips, foldProgress, opacity = 1.0, isGhost = false }) => {
  const { gap, physicsMode, showStress } = params;

  // Convert progress (0..1) to angle (-90deg .. 0deg) relative to flat paper
  // 0 progress = Flat (-90deg)
  // 1 progress = Open (0deg / Upright)
  // The 'top' part of the card rotates.
  const currentAngle = -Math.PI / 2 + (foldProgress * Math.PI / 2);

  const elements = useMemo(() => {
    if (!strips || strips.length === 0) return null;

    const els: React.ReactNode[] = [];

    // Helper to add a strip to the list
    const addStrip = (key: string, w: number, h: number, pos: THREE.Vector3, rot: [number, number, number], col: string, tension = 0) => {
        els.push(
            <group key={key} position={pos} rotation={rot}>
                <PaperStrip width={w} height={h} color={col} tension={tension} isGhost={isGhost} showStress={showStress} opacity={opacity} />
            </group>
        );
    };

    // Calculate bounding box for margins
    const firstStrip = strips[0];
    const lastStrip = strips[strips.length - 1];
    const minX = firstStrip.x - firstStrip.width / 2;
    const maxX = lastStrip.x + lastStrip.width / 2;
    const totalPatternWidth = maxX - minX;

    const marginWidth = Math.max(0, (PAPER_W - totalPatternWidth) / 2);
    const leftMarginX = -PAPER_W/2 + marginWidth/2;
    const rightMarginX = PAPER_W/2 - marginWidth/2;

    const halfH = PAPER_H / 2;

    // --- 1. Static Base Margins (Bottom Half) ---
    // These sit on the Z plane, extending from Y=0 to Y=halfH (in 2D space), mapped to Z in 3D
    const botZ = halfH / 2;
    addStrip('margin_l_bot', marginWidth, halfH, new THREE.Vector3(leftMarginX, 0, botZ), [-Math.PI/2, 0, 0], '#fdfbf7');
    addStrip('margin_r_bot', marginWidth, halfH, new THREE.Vector3(rightMarginX, 0, botZ), [-Math.PI/2, 0, 0], '#fdfbf7');

    // --- 2. Rotating Top Margins (Top Half) ---
    // These rotate around the X-axis at Y=0, Z=0
    const topY = halfH / 2; // relative to the rotated frame

    // We group the top margins so we can rotate them together
    els.push(
        <group key="margins_top" rotation={[currentAngle, 0, 0]}>
            <group position={[leftMarginX, topY, 0]}>
                <PaperStrip width={marginWidth} height={halfH} color='#fdfbf7' isGhost={isGhost} opacity={opacity} />
            </group>
            <group position={[rightMarginX, topY, 0]}>
                <PaperStrip width={marginWidth} height={halfH} color='#fdfbf7' isGhost={isGhost} opacity={opacity} />
            </group>
        </group>
    );

    // --- 3. The Strips ---
    strips.forEach((strip, i) => {
        const x = strip.x;
        const rise = strip.rise;
        const run = strip.run;
        const w = strip.width;

        // Top Sheet Segment (attached to rotating part)
        const topSegLen = halfH - rise;
        if (topSegLen > EPSILON || physicsMode === 'IMPOSSIBLE') {
            const h = Math.max(EPSILON, Math.abs(topSegLen));
            const y = rise + h/2;
            // This is parented to the rotating frame effectively
            els.push(
                <group key={`s_top_${i}`} rotation={[currentAngle, 0, 0]}>
                     <group position={[x, y, 0]}>
                        <PaperStrip width={w} height={h} color="#fdfbf7" isGhost={isGhost} opacity={opacity} />
                     </group>
                </group>
            );
        }

        // Bottom Sheet Segment (static on ground)
        const botSegLen = halfH - run;
        if (botSegLen > EPSILON || physicsMode === 'IMPOSSIBLE') {
            const h = Math.max(EPSILON, Math.abs(botSegLen));
            const z = run + h/2;
            addStrip(`s_bot_${i}`, w, h, new THREE.Vector3(x, 0, z), [-Math.PI/2, 0, 0], "#fdfbf7");
        }

        // --- The Pop-up Mechanism (Knee) ---
        // Anchor on Top Sheet (Rotating)
        // In local rotating frame: (x, rise, 0)
        // In world frame:
        const pTop = new THREE.Vector3(
            x,
            rise * Math.cos(currentAngle),
            rise * Math.sin(currentAngle)
        );

        // Anchor on Bottom Sheet (Static)
        // In world frame: (x, 0, run)
        const pBot = new THREE.Vector3(x, 0, run);

        // Distance between anchors
        const dist = pTop.distanceTo(pBot);
        const maxLen = rise + run;

        let tension = 0;
        if (maxLen > EPSILON) tension = (dist / maxLen - 0.95) * 20; // 0 to 1 range roughly

        // Solve for Knee Position
        // We have triangle sides: rise, run, and chord (dist)
        // If dist > rise + run, it's impossible (broken)
        // If dist is small, it folds inward or outward. We want outward (towards viewer usually, or Y up)

        let pKnee: THREE.Vector3 | null = null;
        let isBroken = false;

        if (dist > maxLen && physicsMode === 'REALISTIC') {
             // Snap (render straight line but maybe colored warning)
             // Just lerp
             pKnee = new THREE.Vector3().lerpVectors(pTop, pBot, rise / maxLen);
             tension = 1.0; 
        } else if (dist > maxLen && physicsMode === 'IMPOSSIBLE') {
             isBroken = true;
             // Just render straight
             pKnee = new THREE.Vector3().lerpVectors(pTop, pBot, rise / maxLen);
        } else {
             // Valid geometric solution exists (intersection of two spheres/circles)
             // Circle 1 center pTop radius rise
             // Circle 2 center pBot radius run
             // Intersection exists because dist <= rise + run
             // Standard Circle Intersection Math

             // Vector from Top to Bot
             const dVec = new THREE.Vector3().subVectors(pBot, pTop); 
             // We work in the 2D plane defined by the strip vertical slice (Y, Z axes essentially)
             // But simpler: we know X is constant.

             const r1 = rise;
             const r2 = run;
             const d = dist;

             // distance from pTop to intersection of radical axis and line of centers
             const a = (r1*r1 - r2*r2 + d*d) / (2*d);

             // distance from line of centers to intersection points
             const h = Math.sqrt(Math.max(0, r1*r1 - a*a));

             // Point P2 (intersection of radical axis)
             const P2 = new THREE.Vector3().copy(pTop).add(dVec.clone().multiplyScalar(a/d));

             // Offsets
             // We need a vector perpendicular to dVec in the YZ plane (since X is constant)
             // dVec = (0, dy, dz) roughly
             // Perp = (0, -dz, dy) or (0, dz, -dy)
             // We want the solution that points "Up/Out". 
             // Usually Y positive is Up.

             const x2 = P2.x;
             const y2 = P2.y;
             const z2 = P2.z;

             const dy = pBot.y - pTop.y;
             const dz = pBot.z - pTop.z;

             // Two solutions for knee
             const knee1 = new THREE.Vector3(x, y2 + h * (dz/d), z2 - h * (dy/d));
             const knee2 = new THREE.Vector3(x, y2 - h * (dz/d), z2 + h * (dy/d));

             // Heuristic: pick the one with higher Y (upwards pop-up) or further from origin?
             // Usually "mountain fold" for the knee implies it sticks OUT.
             // If we look at the standard coordinate system:
             // Flat state: pTop is at Z=-rise? No, our setup is weird.
             // Let's assume the one with higher Y is usually correct for a "Mountain" knee.
             pKnee = (knee1.y > knee2.y) ? knee1 : knee2;
        }

        if (pKnee) {
             const riserColor = isBroken ? '#a855f7' : '#fdfbf7';
             const treadColor = isBroken ? '#d8b4fe' : '#fdfbf7';

             // Riser (Top to Knee)
             const riserVec = new THREE.Vector3().subVectors(pKnee, pTop);
             const riserLen = riserVec.length();
             if (riserLen > EPSILON) {
                 const mid = new THREE.Vector3().addVectors(pTop, pKnee).multiplyScalar(0.5);
                 // Rotation
                 const rotX = Math.atan2(riserVec.z, riserVec.y);
                 addStrip(`riser_${i}`, w, riserLen, mid, [rotX, 0, 0], riserColor, tension);
             }

             // Tread (Knee to Bot)
             const treadVec = new THREE.Vector3().subVectors(pBot, pKnee);
             const treadLen = treadVec.length();
             if (treadLen > EPSILON) {
                 const mid = new THREE.Vector3().addVectors(pKnee, pBot).multiplyScalar(0.5);
                 const rotX = Math.atan2(treadVec.z, treadVec.y);
                 addStrip(`tread_${i}`, w, treadLen, mid, [rotX, 0, 0], treadColor, tension);
             }
        }

        // Gaps (Fillers between strips)
        if (i < strips.length - 1 && gap > 0) {
            const gapX = x + w/2 + gap/2;
            // Bot Gap
            addStrip(`gap_b_${i}`, gap, halfH, new THREE.Vector3(gapX, 0, botZ), [-Math.PI/2, 0, 0], '#fdfbf7');
            // Top Gap (Rotating)
            els.push(
               <group key={`gap_t_${i}`} rotation={[currentAngle, 0, 0]}>
                   <group position={[gapX, topY, 0]}>
                       <PaperStrip width={gap} height={halfH} color='#fdfbf7' isGhost={isGhost} opacity={opacity} />
                   </group>
               </group>
            );
        }

    });

    return els;
  }, [strips, currentAngle, physicsMode, showStress, isGhost, opacity, gap]);

  return <>{elements}</>;
};

// --- Scene ---

const SceneContent: React.FC<Props> = (props) => {
    return (
        <>
            <group position={[0, -50, 0]}>
                <Center top>
                    {props.params.showGhostTrails && (
                        <>
                            <KirigamiMesh {...props} foldProgress={props.foldProgress * 0.3} opacity={0.2} isGhost />
                            <KirigamiMesh {...props} foldProgress={props.foldProgress * 0.6} opacity={0.3} isGhost />
