                blur={2.5} 
                far={100} 
            />

            <OrbitControls 
                minPolarAngle={0} 
                maxPolarAngle={Math.PI / 1.8}
                minDistance={100}
                maxDistance={1200}
                makeDefault
            />
        </>
    );
};

export const Visualizer3D: React.FC<Props> = (props) => {
